struct SegmentTree {

    int n;

    vector<int> node;

    SegmentTree(int n_) {

        n = 1;

        while (n < n_) {

            n *= 2;

        }

        node.assign(2 * n - 1, -1);

    }

    void update(int x, int a) {

        x += n - 1;

        node[x] = a;

        while (x > 0) {

            x = (x - 1) / 2;

            chmax(node[x], a);

        }

    }

    int query(int a, int b, int k = 0, int l = 0, int r = -1) {

        if (r < 0) r = n;

        if (r <= a || b <= l) return -1;

        if (a <= l && r <= b) return node[k];

        int vl = query(a, b, 2 * k + 1, l, (l + r) / 2);

        int vr = query(a, b, 2 * k + 2, (l + r) / 2, r);

        return max(vl, vr);

    }

};

