    long long ans = v[0];

    for (int i = 1; i < (int) v.size(); ++i) {

        ans = gcd(ans, v[i]);

    }

    return ans;

}



long long lcm(long long a, long long b) {

    long long g = gcd(a, b);

    return a / g * b;

}



