      return r < another.r;

    }

    else{

      return l > another.l; // 

    }

  }



  string ToString(){

    stringstream ss;

    ss << l << ' ' << r << ' ' << type;

    return ss.str();

  }

};



const int BRIDGE = 0;

const int QUERY = 1;



int main(){

    cin.tie(0);

    ios::sync_with_stdio(false);



    int N,Q; 

    cin>>N>>Q;



    vector<Query> V;



    VV G(N);

    rep(i,N){

      ll c;cin>>c;c--;

      G[c].push_back(i);

    }

    rep(i,N){

      if(G[i].size()<2) continue;

      rep(j,SZ(G[i])-1){

        ll from = G[i][j];

        ll to = G[i][j+1];

        V.push_back({from, to, BRIDGE});

      }

    }

    rep(i,Q){

      ll l,r;cin>>l>>r;

      l--;r--;

      V.push_back({l,r,QUERY,i});

    }

    sort(ALL(V));



    VI Ans(Q);

    BIT bit(N);



    for(auto v : V){

      if(v.type==BRIDGE){

        bit.add(v.r, 1);

      }

      else{

        ll all = v.r - v.l + 1;

        ll m = bit.sum(v.r);

        Ans[v.query_id] = all-m;

      }

    }



    rep(i,Q){

      p(Ans[i]);

    }



    return 0;

}
